#include <stdio.h>
#include <stdbool.h>
#include <math.h>

bool is_prime(int num) {
    if (num <= 1) return false;
    if (num == 2) return true;
    if (num % 2 == 0) return false;
    for (int i = 3; i * i <= num; i += 2) {
        if (num % i == 0) return false;
    }
    return true;
}

int next_prime(int num) {
    num++;
    while (!is_prime(num)) num++;
    return num;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int passwords[N][N];
        bool cracked[N][N];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                scanf("%d", &passwords[i][j]);
                cracked[i][j] = false;
            }
        }
        int unsuccessful_tries = 0;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                if (!cracked[i][j]) {
                    if (is_prime(passwords[i][j])) {
                        // Try prime numbers
                        int prime = 2;
                        while (prime < passwords[i][j]) {
                            unsuccessful_tries++;
                            prime = next_prime(prime);
                        }
                    } else {
                        // Try even numbers
                        int even = 0;
                        while (even < passwords[i][j]) {
                            unsuccessful_tries++;
                            even += 2;
                        }
                        if (even > passwords[i][j]) {
                            // Try odd numbers
                            int odd = even - 1;
                            while (odd > passwords[i][j]) {
                                unsuccessful_tries++;
                                odd -= 2;
                            }
                        }
                    }
                    // Mark connected servers as cracked
                    for (int x = i; x < N; x++) {
                        for (int y = j; y < N; y++) {
                            if (passwords[x][y] == passwords[i][j]) {
                                cracked[x][y] = true;
                            }
                        }
                    }
                }
            }
        }
        printf("%d\n", unsuccessful_tries);
    }
    return 0;
}

